    //     `Variation of <sourceExerciseId>` set in createOutputExercise.
    const existingOutputExercises = await payload.find({
      collection: 'exercises',
      where: { lesson: { equals: outputLessonId } },
      limit: 0,
      depth: 0,
      overrideAccess: true,
