    return finalStatus
  } catch (err) {
    logger.error({ duplicationId, err }, 'Orchestrator run failed')
    await payload.update({
      collection: 'lesson-duplications',
      id: duplicationId,
      data: { status: 'failed' },
      overrideAccess: true,
    })
    throw err
  }
}

