    }

    const processedIds = new Set<string>([
      ...((duplication.outputExercises as unknown as OutputExerciseMapping[]) ?? []).map(
        (m) => m.sourceExerciseId,
      ),
      ...((duplication.failures as unknown as Array<{ exerciseRef: string }>) ?? []).map(
        (f) => f.exerciseRef,
