    const chapter = await payload.create({
      collection: 'chapters',
      data: {
        title: `Orch Chapter ${ts}`,
        chapterLabel: `OCH-${ts}`,
        course: courseId,
        order: 0,
        status: 'published',
        isActive: true,
        tenant: tenantId,
        locale: 'he',
      },
    })
    chapterId = chapter.id

    const lesson = await payload.create({
      collection: 'lessons',
      data: {
        title: `Orch Source Lesson ${ts}`,
        chapter: chapterId,
        type: 'practice',
        order: 1,
        status: 'published',
        isActive: true,
        tenant: tenantId,
        locale: 'he',
        accessType: 'inherit',
        contentStatus: 'none',
        contentStatusVisible: true,
      },
      draft: false,
    })
    sourceLessonId = lesson.id
    cleanupLessonIds.push(sourceLessonId)

    // Create exactly 5 exercises on the source lesson
    for (let i = 0; i < 5; i++) {
      const ex = await payload.create({
        collection: 'exercises',
        data: { title: `Orch Exercise ${i} ${ts}`, lesson: sourceLessonId },
        draft: true,
      })
      cleanupExerciseIds.push(ex.id)
    }
